// validation.js — reusable input-validation helpers

/**
 * Validate that `value` is a finite integer (accepts numbers and numeric strings).
 * Returns true when valid, false otherwise.
 */
function isNumericId(value) {
  if (value === undefined || value === null || value === '') return false;
  const n = Number(value);
  return Number.isFinite(n) && Number.isInteger(n) && n > 0;
}

/**
 * Validate an email address.
 * Follows RFC 5321/5322 practical limits:
 *   - local part + '@' + domain must be present
 *   - max 254 characters total
 */
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
function isValidEmail(value) {
  if (typeof value !== 'string') return false;
  return EMAIL_REGEX.test(value) && value.length <= 254;
}

/**
 * Validate a display name string.
 *   - Must be a non-empty string
 *   - Length: 1–100 characters
 */
function isValidName(value) {
  return typeof value === 'string' && value.trim().length >= 1 && value.length <= 100;
}

// ---------------------------------------------------------------------------
// Validator factories — each returns an array of error message strings.
// An empty array means "all checks passed".
// ---------------------------------------------------------------------------

/**
 * Validate a route/query parameter that must be a positive integer ID.
 * @param {string} paramName  — human-readable field name for error messages
 * @param {*}      value      — raw value from req.params / req.query
 */
function validateId(paramName, value) {
  const errors = [];
  if (value === undefined || value === null || value === '') {
    errors.push(`'${paramName}' is required`);
  } else if (!isNumericId(value)) {
    errors.push(`'${paramName}' must be a positive integer`);
  }
  return errors;
}

/**
 * Validate a name field from a request body.
 * @param {string} fieldName  — human-readable field name
 * @param {*}      value      — raw value from req.body
 * @param {object} [opts]
 * @param {boolean} [opts.required=true]  — treat absence as an error
 */
function validateName(fieldName, value, { required = true } = {}) {
  const errors = [];
  const missing = value === undefined || value === null || value === '';

  if (missing) {
    if (required) errors.push(`'${fieldName}' is required`);
    return errors; // no further checks if value is absent
  }

  if (typeof value !== 'string') {
    errors.push(`'${fieldName}' must be a string`);
    return errors;
  }

  if (value.trim().length < 1) {
    errors.push(`'${fieldName}' must not be blank`);
  } else if (value.length > 100) {
    errors.push(`'${fieldName}' must be at most 100 characters`);
  }

  return errors;
}

/**
 * Validate an email field from a request body.
 * @param {string} fieldName  — human-readable field name
 * @param {*}      value      — raw value from req.body
 * @param {object} [opts]
 * @param {boolean} [opts.required=true]
 */
function validateEmail(fieldName, value, { required = true } = {}) {
  const errors = [];
  const missing = value === undefined || value === null || value === '';

  if (missing) {
    if (required) errors.push(`'${fieldName}' is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`'${fieldName}' must be a string`);
    return errors;
  }

  if (value.length > 254) {
    errors.push(`'${fieldName}' must be at most 254 characters`);
  } else if (!EMAIL_REGEX.test(value)) {
    errors.push(`'${fieldName}' must be a valid email address`);
  }

  return errors;
}

/**
 * Convenience: send a 400 response when there are validation errors.
 * Returns true if an error was sent so the caller can return early.
 *
 * @param {import('express').Response} res
 * @param {string[]} errors
 * @returns {boolean}
 */
function sendValidationErrors(res, errors) {
  if (errors.length === 0) return false;
  res.status(400).json({
    error: 'Validation failed',
    details: errors,
  });
  return true;
}

module.exports = {
  isNumericId,
  isValidEmail,
  isValidName,
  validateId,
  validateName,
  validateEmail,
  sendValidationErrors,
};

