/**
 * validation.js
 * Reusable input-validation helpers for API route handlers.
 *
 * Each validator returns an array of error strings (empty = valid).
 * Use `collectErrors` to build a structured 400 response.
 */

'use strict';

// ---------------------------------------------------------------------------
// Individual field validators
// ---------------------------------------------------------------------------

/**
 * Validate `id` path/query parameter.
 * Must be present and parse as a finite integer > 0.
 */
function validateId(value, fieldName = 'id') {
  const errors = [];
  if (value === undefined || value === null || value === '') {
    errors.push(`'${fieldName}' is required`);
    return errors;            // further checks don't make sense
  }
  const num = Number(value);
  if (!Number.isFinite(num) || !Number.isInteger(num)) {
    errors.push(`'${fieldName}' must be a numeric integer (received: ${JSON.stringify(value)})`);
  } else if (num <= 0) {
    errors.push(`'${fieldName}' must be a positive integer`);
  }
  return errors;
}

/**
 * Validate a `name` field.
 * Must be a non-empty string between 1 and 100 characters.
 */
function validateName(value, fieldName = 'name') {
  const errors = [];
  if (value === undefined || value === null) {
    errors.push(`'${fieldName}' is required`);
    return errors;
  }
  if (typeof value !== 'string') {
    errors.push(`'${fieldName}' must be a string (received: ${typeof value})`);
    return errors;
  }
  const trimmed = value.trim();
  if (trimmed.length < 1) {
    errors.push(`'${fieldName}' must not be empty`);
  } else if (trimmed.length > 100) {
    errors.push(`'${fieldName}' must be at most 100 characters (received: ${trimmed.length})`);
  }
  return errors;
}

/**
 * Validate an `email` field.
 * Must be a string, match a valid e-mail format, and be ≤ 254 characters
 * (RFC 5321 maximum).
 */
const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

function validateEmail(value, fieldName = 'email') {
  const errors = [];
  if (value === undefined || value === null) {
    errors.push(`'${fieldName}' is required`);
    return errors;
  }
  if (typeof value !== 'string') {
    errors.push(`'${fieldName}' must be a string (received: ${typeof value})`);
    return errors;
  }
  if (value.length > 254) {
    errors.push(`'${fieldName}' must be at most 254 characters (received: ${value.length})`);
  }
  if (!EMAIL_RE.test(value)) {
    errors.push(`'${fieldName}' must be a valid email address (received: ${JSON.stringify(value)})`);
  }
  return errors;
}

// ---------------------------------------------------------------------------
// Composite validators for common request shapes
// ---------------------------------------------------------------------------

/**
 * Validate the body of a "create user" (POST /users) request.
 * Required: name, email.
 */
function validateCreateUser(body) {
  return [
    ...validateName(body.name),
    ...validateEmail(body.email),
  ];
}

/**
 * Validate the body of an "update user" (PUT /users/:id) request.
 * id comes from the URL params; name and email are optional but, if
 * provided, must be valid.
 */
function validateUpdateUser(params, body) {
  const errors = [...validateId(params.id)];

  // Only validate fields that were actually supplied in the body
  if (body.name !== undefined) {
    errors.push(...validateName(body.name));
  }
  if (body.email !== undefined) {
    errors.push(...validateEmail(body.email));
  }
  if (body.name === undefined && body.email === undefined) {
    errors.push("Request body must include at least one field to update ('name' or 'email')");
  }
  return errors;
}

/**
 * Validate a URL parameter that is expected to be a numeric id.
 */
function validateIdParam(params, fieldName = 'id') {
  return validateId(params[fieldName], fieldName);
}

// ---------------------------------------------------------------------------
// Response helper
// ---------------------------------------------------------------------------

/**
 * If `errors` is non-empty, send a 400 response with the error list and
 * return true (so the caller can `return` immediately).
 * Otherwise return false.
 *
 * @param {string[]} errors
 * @param {import('express').Response} res
 * @returns {boolean}
 */
function sendValidationErrors(errors, res) {
  if (errors.length === 0) return false;
  res.status(400).json({
    error: 'Validation failed',
    details: errors,
  });
  return true;
}

// ---------------------------------------------------------------------------
// Exports
// ---------------------------------------------------------------------------

module.exports = {
  validateId,
  validateName,
  validateEmail,
  validateCreateUser,
  validateUpdateUser,
  validateIdParam,
  sendValidationErrors,
};

