// validation.js – reusable input-validation helpers

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validate a user ID from a route parameter.
 *
 * @param {string} rawId  – value straight from req.params
 * @returns {{ errors: string[], id: number|null }}
 */
function validateUserId(rawId) {
  const errors = [];

  if (rawId === undefined || rawId === null || rawId === '') {
    errors.push('id is required');
    return { errors, id: null };
  }

  const id = Number(rawId);
  if (!Number.isInteger(id) || id <= 0) {
    errors.push('id must be a positive integer');
    return { errors, id: null };
  }

  return { errors, id };
}

/**
 * Validate the user body fields sent in POST / PUT requests.
 *
 * @param {object}  body            – req.body
 * @param {object}  [opts]
 * @param {boolean} [opts.requireAll=true]  – when false (PATCH/PUT), only
 *                                            validate fields that are present
 * @returns {{ errors: string[], data: object }}
 */
function validateUserBody(body, { requireAll = true } = {}) {
  const errors = [];
  const data = {};

  // ── name ──────────────────────────────────────────────────────────────────
  const namePresent = Object.prototype.hasOwnProperty.call(body, 'name');

  if (requireAll && !namePresent) {
    errors.push('name is required');
  } else if (namePresent) {
    const { name } = body;

    if (typeof name !== 'string') {
      errors.push('name must be a string');
    } else if (name.trim().length < 1) {
      errors.push('name must be at least 1 character');
    } else if (name.length > 100) {
      errors.push('name must be at most 100 characters');
    } else {
      data.name = name.trim();
    }
  }

  // ── email ─────────────────────────────────────────────────────────────────
  const emailPresent = Object.prototype.hasOwnProperty.call(body, 'email');

  if (requireAll && !emailPresent) {
    errors.push('email is required');
  } else if (emailPresent) {
    const { email } = body;

    if (typeof email !== 'string') {
      errors.push('email must be a string');
    } else if (email.length > 254) {
      errors.push('email must be at most 254 characters');
    } else if (!EMAIL_REGEX.test(email)) {
      errors.push('email must be a valid email address');
    } else {
      data.email = email.toLowerCase().trim();
    }
  }

  return { errors, data };
}

/**
 * Send a 400 response that lists every validation error.
 *
 * @param {import('express').Response} res
 * @param {string[]} errors
 */
function sendValidationError(res, errors) {
  res.status(400).json({
    error: 'Validation failed',
    details: errors,
  });
}

module.exports = { validateUserId, validateUserBody, sendValidationError };

