// validation.js — reusable input validation helpers

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validate a user id route parameter.
 * Must be present and parse as a positive integer.
 *
 * @param {string} value - raw value from req.params
 * @returns {string|null} error message, or null when valid
 */
function validateId(value) {
  if (value === undefined || value === null || value === '') {
    return 'id is required';
  }
  const num = Number(value);
  if (!Number.isInteger(num) || num <= 0) {
    return 'id must be a positive integer';
  }
  return null;
}

/**
 * Validate a name field.
 * Must be a non-empty string between 1 and 100 characters.
 *
 * @param {*} value - value from request body
 * @returns {string|null} error message, or null when valid
 */
function validateName(value) {
  if (value === undefined || value === null) {
    return 'name is required';
  }
  if (typeof value !== 'string') {
    return 'name must be a string';
  }
  const trimmed = value.trim();
  if (trimmed.length < 1) {
    return 'name must be at least 1 character';
  }
  if (trimmed.length > 100) {
    return 'name must be at most 100 characters';
  }
  return null;
}

/**
 * Validate an email field.
 * Must be a string that matches a basic email pattern and is at most 254 chars.
 *
 * @param {*} value - value from request body
 * @returns {string|null} error message, or null when valid
 */
function validateEmail(value) {
  if (value === undefined || value === null) {
    return 'email is required';
  }
  if (typeof value !== 'string') {
    return 'email must be a string';
  }
  if (value.length > 254) {
    return 'email must be at most 254 characters';
  }
  if (!EMAIL_REGEX.test(value)) {
    return 'email must be a valid email address';
  }
  return null;
}

/**
 * Validate a full user body for creation (all fields required).
 *
 * @param {object} body - req.body
 * @returns {{ valid: boolean, errors: string[] }}
 */
function validateCreateUser(body) {
  const errors = [];

  const nameError = validateName(body.name);
  if (nameError) errors.push(nameError);

  const emailError = validateEmail(body.email);
  if (emailError) errors.push(emailError);

  return { valid: errors.length === 0, errors };
}

/**
 * Validate a partial user body for updates (only validate fields that are present).
 * At least one field must be provided.
 *
 * @param {object} body - req.body
 * @returns {{ valid: boolean, errors: string[] }}
 */
function validateUpdateUser(body) {
  const errors = [];
  const hasName = body.name !== undefined;
  const hasEmail = body.email !== undefined;

  if (!hasName && !hasEmail) {
    errors.push('at least one field (name, email) must be provided for update');
    return { valid: false, errors };
  }

  if (hasName) {
    const nameError = validateName(body.name);
    if (nameError) errors.push(nameError);
  }

  if (hasEmail) {
    const emailError = validateEmail(body.email);
    if (emailError) errors.push(emailError);
  }

  return { valid: errors.length === 0, errors };
}

/**
 * Validate a numeric id route parameter (wraps validateId into the standard result shape).
 *
 * @param {string} value - raw value from req.params.id
 * @returns {{ valid: boolean, errors: string[] }}
 */
function validateIdParam(value) {
  const error = validateId(value);
  if (error) return { valid: false, errors: [error] };
  return { valid: true, errors: [] };
}

module.exports = {
  validateIdParam,
  validateCreateUser,
  validateUpdateUser,
};

