/**
 * Validation helper module.
 * Each exported function returns an array of error message strings.
 * An empty array means all checks passed.
 */

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validate a user ID supplied as a route parameter (string from Express).
 * @param {string} raw - The raw value from req.params.id
 * @returns {string[]} Validation errors
 */
function validateId(raw) {
  const errors = [];
  if (raw === undefined || raw === null || raw === '') {
    errors.push('id is required');
    return errors;
  }
  if (!/^\d+$/.test(String(raw)) || Number(raw) <= 0) {
    errors.push('id must be a positive integer');
  }
  return errors;
}

/**
 * Validate the user body fields (name, email).
 * @param {object} body        - req.body
 * @param {boolean} allRequired - When true both fields must be present (POST).
 *                                When false only supplied fields are validated (PATCH/PUT).
 * @returns {string[]} Validation errors
 */
function validateUserBody(body, allRequired = true) {
  const errors = [];
  const { name, email } = body || {};

  // ── name ────────────────────────────────────────────────────────────────────
  if (allRequired && (name === undefined || name === null || name === '')) {
    errors.push('name is required');
  } else if (name !== undefined && name !== null) {
    if (typeof name !== 'string') {
      errors.push('name must be a string');
    } else {
      if (name.trim().length < 1) {
        errors.push('name must be at least 1 character');
      }
      if (name.length > 100) {
        errors.push('name must be at most 100 characters');
      }
    }
  }

  // ── email ───────────────────────────────────────────────────────────────────
  if (allRequired && (email === undefined || email === null || email === '')) {
    errors.push('email is required');
  } else if (email !== undefined && email !== null) {
    if (typeof email !== 'string') {
      errors.push('email must be a string');
    } else {
      if (email.length > 254) {
        errors.push('email must be at most 254 characters');
      }
      if (!EMAIL_REGEX.test(email)) {
        errors.push('email must be a valid email address');
      }
    }
  }

  return errors;
}

/**
 * Express middleware factory: validates req.params.id and short-circuits with
 * a 400 response if invalid.
 */
function validateIdParam(req, res, next) {
  const errors = validateId(req.params.id);
  if (errors.length > 0) {
    return res.status(400).json({ errors });
  }
  next();
}

/**
 * Express middleware factory: validates req.body for a full user object
 * (all fields required – use for POST).
 */
function validateUserBodyRequired(req, res, next) {
  const errors = validateUserBody(req.body, true);
  if (errors.length > 0) {
    return res.status(400).json({ errors });
  }
  next();
}

/**
 * Express middleware factory: validates req.body fields only when present
 * (use for PUT/PATCH where some fields may be omitted).
 */
function validateUserBodyPartial(req, res, next) {
  const errors = validateUserBody(req.body, false);
  if (errors.length > 0) {
    return res.status(400).json({ errors });
  }
  next();
}

module.exports = {
  validateId,
  validateUserBody,
  validateIdParam,
  validateUserBodyRequired,
  validateUserBodyPartial,
};

